import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './Auth.css';

const Register = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const { name, email, password, confirmPassword } = formData;

    if (!name.trim() || !email.trim() || !password || !confirmPassword) {
      setError('All fields are required.');
      return;
    }

    if (name.trim().length < 2) {
      setError('Name must be at least 2 characters long.');
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters long.');
      return;
    }

    if (password !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    try {
      setLoading(true);
      setError('');

      const { data } = await axios.post('/api/auth/register', {
        name: name.trim(),
        email: email.trim(),
        password
      });

      login(data.user, data.token);
      navigate('/', { replace: true });
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const getPasswordStrength = (pass) => {
    if (!pass) return null;
    if (pass.length < 6) return { level: 'weak', label: 'Too short', color: '#ef4444' };
    if (pass.length < 8) return { level: 'fair', label: 'Fair', color: '#f59e0b' };
    if (/(?=.*[a-z])(?=.*[A-Z])(?=.*[0-9])/.test(pass)) {
      return { level: 'strong', label: 'Strong', color: '#10b981' };
    }
    return { level: 'good', label: 'Good', color: '#22c55e' };
  };

  const strength = getPasswordStrength(formData.password);

  return (
    <div className="auth-page">
      <div className="auth-bg">
        <div className="auth-orb auth-orb-1"></div>
        <div className="auth-orb auth-orb-2"></div>
      </div>

      <div className="auth-container" id="register-form-container">
        <div className="auth-header">
          <div className="auth-icon">🚀</div>
          <h1 className="auth-title">Create account</h1>
          <p className="auth-subtitle">Join FundIt and start making an impact</p>
        </div>

        {error && (
          <div className="alert alert-error" id="register-error-alert" role="alert">
            <span>⚠️</span>
            <p>{error}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} noValidate id="register-form">
          <div className="form-group">
            <label className="form-label" htmlFor="register-name">Full Name</label>
            <input
              id="register-name"
              name="name"
              type="text"
              className="form-input"
              placeholder="John Doe"
              value={formData.name}
              onChange={handleChange}
              autoComplete="name"
              required
            />
          </div>

          <div className="form-group">
            <label className="form-label" htmlFor="register-email">Email Address</label>
            <input
              id="register-email"
              name="email"
              type="email"
              className="form-input"
              placeholder="you@example.com"
              value={formData.email}
              onChange={handleChange}
              autoComplete="email"
              required
            />
          </div>

          <div className="form-group">
            <label className="form-label" htmlFor="register-password">Password</label>
            <input
              id="register-password"
              name="password"
              type="password"
              className="form-input"
              placeholder="Min. 6 characters"
              value={formData.password}
              onChange={handleChange}
              autoComplete="new-password"
              required
            />
            {strength && (
              <div className="password-strength" id="password-strength-indicator">
                <div className="strength-bar">
                  <div
                    className="strength-fill"
                    style={{
                      width: strength.level === 'weak' ? '25%' : strength.level === 'fair' ? '50%' : strength.level === 'good' ? '75%' : '100%',
                      background: strength.color
                    }}
                  ></div>
                </div>
                <span style={{ color: strength.color, fontSize: '0.8rem', fontWeight: 600 }}>
                  {strength.label}
                </span>
              </div>
            )}
          </div>

          <div className="form-group">
            <label className="form-label" htmlFor="register-confirm-password">Confirm Password</label>
            <input
              id="register-confirm-password"
              name="confirmPassword"
              type="password"
              className="form-input"
              placeholder="Re-enter your password"
              value={formData.confirmPassword}
              onChange={handleChange}
              autoComplete="new-password"
              required
            />
            {formData.confirmPassword && formData.password !== formData.confirmPassword && (
              <span style={{ color: '#fca5a5', fontSize: '0.8rem' }}>
                ✗ Passwords don't match
              </span>
            )}
            {formData.confirmPassword && formData.password === formData.confirmPassword && (
              <span style={{ color: '#6ee7b7', fontSize: '0.8rem' }}>
                ✓ Passwords match
              </span>
            )}
          </div>

          <button
            type="submit"
            className="btn btn-primary btn-full"
            disabled={loading}
            id="btn-register-submit"
          >
            {loading ? (
              <>
                <span className="spinner"></span>
                Creating account...
              </>
            ) : (
              'Create Account'
            )}
          </button>
        </form>

        <div className="auth-footer">
          <p>
            Already have an account?{' '}
            <Link to="/login" id="link-to-login">
              Log in
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Register;
